(3963, 3, 1847, 'recommendation', 'a suggestion or proposal as to the best course of action, especially one put forward by an authoritative body.'),
(3964, 3, 455, 'lean', 'be in or move into a sloping position.'),
(3965, 3, 3033, 'recreation', 'activity done for enjoyment when one is not working.'),
(3966, 3, 2756, 'covering', 'a thing used to cover something else, typically in order to protect or conceal it.'),
(3967, 3, 1536, 'refined', 'with impurities or unwanted elements having been removed by processing.'),
(3968, 3, 2219, 'reflect', '(of a surface or body) throw back (heat, light, or sound) without absorbing it.'),
(3969, 3, 3032, 'reflection', 'the throwing back by a body or surface of light, heat, or sound without absorbing it.'),
(3970, 3, 798, 'reform', 'make changes in (something, typically a social, political, or economic institution or practice) in order to improve it.'),
(3972, 3, 2506, 'booster', 'a source of help or encouragement.'),
(3973, 3, 210, 'central shelter', 'shelter'),
(3975, 3, 2340, 'lightning', 'the occurrence of a natural electrical discharge of very short duration and high voltage between a cloud and the ground or within a cloud, accompanied by a bright flash and typically also thunder.'),
(3976, 3, 3030, 'repair', 'fix or mend (a thing suffering from damage or a fault).'),
(3977, 3, 2866, 'fix', 'fasten (something) securely in a particular place or position.'),
(3978, 3, 3029, 'repetition', 'the action of repeating something that has already been said or written.'),
(3979, 1, 1882, 'representation', 'the action of speaking or acting on behalf of someone or the state of being so represented.'),
(3980, 3, 2664, 'breed', '(of animals) mate and then produce offspring.'),
(3981, 3, 2834, 'endurance', 'the fact or power of enduring an unpleasant or difficult process or situation without giving way.'),
(3982, 3, 1667, 'respect', 'a feeling of deep admiration for someone or something elicited by their abilities, qualities, or achievements.'),
(3983, 3, 1515, 'portrait', 'a painting, drawing, photograph, or engraving of a person, especially one depicting only the face or head and shoulders.'),
(3984, 3, NULL, 'rail', 'a bar or series of bars, typically fixed on upright supports, serving as part of a fence or barrier or used to hang things on.'),
(3985, 3, NULL, 'wealth', 'an abundance of valuable possessions or money.'),
(3986, 3, 2554, 'rivalry', 'competition for the same objective or for superiority in the same field.'),
(3988, 3, 2555, 'rupture', '(especially of a pipe, a vessel, or a bodily part such as an organ or membrane) break or burst suddenly.'),
(3989, 3, 1065, 'flavor', 'the distinctive taste of a food or drink.'),
(3990, 3, 3020, 'satiated', 'another term for sate.'),
(3991, 3, 3083, 'hop', '(of a person) move by jumping on one foot.'),
(3992, 3, 3015, 'serve', 'perform duties or services for (another person or an organization).'),
(3993, 3, 1845, 'frying pan', 'a shallow pan with a long handle, used for cooking food in hot fat or oil.'),
(3994, 3, 2357, 'satin', 'a smooth, glossy fabric produced by a weave in which the threads of the warp are caught and looped by the weft only at certain intervals.'),
(3995, 3, 2096, 'productive sector', 'productive industry'),
(3996, 3, 2556, 'kidnapping', 'the action of abducting someone and holding them captive.'),
(3997, 3, 1801, 'follow-up', 'a continuation or repetition of something that has already been started or done.'),
(3998, 3, 2917, 'zigzag', 'a line or course having abrupt alternate right and left turns.'),
(3999, 3, 2260, 'mandatory', 'required by law or rules; compulsory.'),
(4001, 3, 265, 'live', 'remain alive.'),
(4002, 3, NULL, 'vitality', 'the state of being strong and active; energy.'),
(4003, 3, NULL, 'visit', 'go to see and spend time with (someone) socially.'),
(4006, 3, NULL, 'violence', 'behavior involving physical force intended to hurt, damage, or kill someone or something.'),
(4008, 3, 195, 'bond', 'a relationship between people or groups based on shared feelings, interests, or experiences.'),
(4009, 3, 724, 'life', 'the condition that distinguishes animals and plants from inorganic matter, including the capacity for growth, reproduction, functional activity, and continual change preceding death.'),
(4010, 3, NULL, 'victory', 'an act of defeating an enemy or opponent in a battle, game, or other competition.'),
(4011, 3, NULL, 'via', 'traveling through (a place) en route to a destination.'),
(4013, 3, 3022, 'sale', 'the exchange of a commodity for money; the action of selling something.'),
(4014, 3, 1661, 'sell', 'give or hand over (something) in exchange for money.'),
(4015, 3, 2916, 'hawker', 'a person who travels around selling goods, typically advertising them by shouting.'),
(4016, 3, 1659, 'seller', 'a person who sells something.'),
(4017, 3, 1227, 'candle', 'a cylinder or block of wax or tallow with a central wick that is lit to produce light as it burns.'),
(4018, 3, 2159, 'boat', 'a ship, boat, or locomotive powered by steam.'),
(4019, 3, 2769, 'current value', 'present value'),
(4020, 3, 2772, 'date value', 'value that day'),
(4021, 3, 2559, 'verdict', 'a decision on a disputed issue in a civil or criminal case or an inquest.'),
(4022, 3, 3026, 'ring', 'a small circular band, typically of precious metal and often set with one or more gemstones, worn on a finger as an ornament or a token of marriage, engagement, or authority.'),
(4024, 3, 2579, 'about', 'on the subject of; concerning.'),
(4025, 3, NULL, 'damage', 'physical harm caused to something in such a way as to impair its value, usefulness, or normal function.'),
(4026, 3, NULL, 'tasteless', 'lacking flavor.'),
(4027, 3, 2955, 'tyranny', 'cruel and oppressive government or rule.'),
(4028, 3, 2300, 'timer', 'an automatic mechanism for activating a device at a preset time.'),
(4029, 3, 3139, 'only', 'and no one or nothing more besides; solely or exclusively.'),
(4031, 3, 1871, 'again', 'another time; once more.'),
(4032, 3, 2187, 'approximately', 'used to show that something is almost, but not completely, accurate or exact; roughly.'),
(4033, 3, 2207, 'talent', 'natural aptitude or skill.'),
(4034, 3, 998, 'cut', 'make an opening, incision, or wound in (something) with a sharp-edged tool or object.'),
(4035, 1, NULL, 'sister-in-law', 'a woman who called that married with some one in the family'),
(4036, 3, 2560, 'sip', 'drink (something) by taking small mouthfuls.'),
(4037, 3, 2104, 'wagon', 'a vehicle used for transporting goods or another specified purpose.'),
(4039, 3, 2947, 'utopian', 'modeled on or aiming for a state in which everything is perfect; idealistic.'),
(4040, 3, 2052, 'utopia', 'an imagined place or state of things in which everything is perfect.'),
(4041, 3, 2948, 'uterus', 'the organ in the lower body of a woman or female mammal where offspring are conceived and in which they gestate before birth; the womb.'),
(4042, 3, 2949, 'urology', 'the branch of medicine and physiology concerned with the function and disorders of the urinary system.'),
(4043, 3, 2918, 'you', 'used to refer to the person or people that the speaker is addressing.'),
(4044, 3, NULL, 'barter', 'exchange (goods or services) for other goods or services without using money.'),
(4045, 3, 3024, 'sad', 'feeling or showing sorrow; unhappy.'),
(4046, 3, 2068, 'sorry', 'feeling distress, especially through sympathy with someone else\'s misfortune.'),
(4048, 3, 1861, 'treatment', 'the manner in which someone behaves toward or deals with someone or something.'),
(4049, 3, NULL, 'quiet', 'making little or no noise.'),
(4050, 3, NULL, 'tolerance', 'the ability or willingness to tolerate something, in particular the existence of opinions or behavior that one does not necessarily agree with.'),
(4051, 3, 3009, 'shy', 'being reserved or having or showing nervousness or timidity in the company of other people.'),
(4052, 3, 1872, 'textile', 'a type of cloth or woven fabric.'),
(4053, 3, 1730, 'witness', 'a person who sees an event, typically a crime or accident, take place.'),
(4054, 3, 2348, 'tennis', 'a game in which two or four players strike a ball with rackets over a net stretched across a court. the usual form (originally called lawn tennis ) is played with a felt-covered hollow rubber ball on a grass, clay, or artificial surface.'),
(4055, 3, 2044, 'first lieutenant', 'a commissioned officer in the us army, air force, or marine corps ranking above second lieutenant and below captain.'),
(4056, 3, NULL, 'technical', 'relating to a particular subject, art, or craft, or its techniques.'),
(4057, 3, 3048, 'plug', 'an obstruction blocking a hole, pipe, etc.'),
(4058, 3, 2999, 'stem', 'the main body or stalk of a plant or shrub, typically rising above ground but occasionally subterranean.'),
(4059, 3, 3019, 'scare', 'cause great fear or nervousness in; frighten.'),
(4060, 3, 3054, 'overlap', 'extend over so as to cover partly.'),
(4061, 3, 2040, 'superiority', 'the state of being superior.'),
(4062, 3, 2035, 'superior', 'higher in rank, status, or quality.'),
(4063, 3, 1747, 'luck', 'success or failure apparently brought by chance rather than through one\'s own actions.'),
(4064, 3, 3002, 'sole', 'the undersurface of a person\'s foot.'),
(4065, 3, NULL, 'successively', 'immediately one after another.'),
(4066, 3, NULL, 'surprised', 'feeling or showing surprise.'),
(4067, 3, NULL, 'surprise', 'an unexpected or astonishing event, fact, or thing.'),
(4068, 3, 1983, 'sleepwalker', 'somnambulist'),
(4069, 3, 2064, 'upon', 'more formal term for on, especially in abstract senses.'),
(4071, 3, NULL, 'synchronization', 'the operation or activity of two or more things at the same time or rate.'),
(4072, 3, NULL, 'unplanked', 'without plank'),
(4073, 3, NULL, 'sugar-free', 'without sugar'),
(4074, 3, 143, 'simple', 'easily understood or done; presenting no difficulty.'),
(4075, 3, 3003, 'snap', 'break or cause to break suddenly and completely, typically with a sharp cracking sound.'),
(4076, 3, 2339, 'snake', 'a long limbless reptile which has no eyelids, a short tail, and jaws that are capable of considerable extension. some snakes have a venomous bite.'),
(4077, 3, 2156, 'sermon', 'a talk on a religious or moral subject, especially one given during a church service and based on a passage from the bible.'),
(4078, 3, 1687, 'series', 'a number of things, events, or people of a similar kind or related nature coming one after another.'),
(4079, 3, 2026, 'produce', 'make or manufacture from components or raw materials.'),
(4080, 3, 2460, 'be', 'exist'),
(4082, 3, 123, 'lady', 'a woman (used as a polite or old-fashioned form of reference).'),
(4083, 3, 2098, 'production permit', 'production license'),
(4086, 3, NULL, 'unique', 'being the only one of its kind; unlike anything else.'),
(4087, 3, 2747, 'conviction', 'a formal declaration that someone is guilty of a criminal offense, made by the verdict of a jury or the decision of a judge in a court of law.');
INSERT INTO `english_words` (`id`, `language_id`, `turkish_word_id`, `en_word`, `description`) VALUES
(4088, 3, 2736, 'condition', 'the state of something with regard to its appearance, quality, or working order.'),
(4089, 3, 2822, 'set', 'put, lay, or stand (something) in a specified place or position.'),
(4090, 3, 1876, 'contact', 'the state or condition of physical touching.'),
(4091, 3, 1668, 'count', 'determine the total number of (a collection of items).'),
(4092, 3, 2571, 'contest', 'an event in which people compete for supremacy in a sport, activity, or particular quality.'),
(4093, 3, 2147, 'emphasis', 'special importance, value, or prominence given to something.'),
(4094, 3, 2572, 'contradict', 'deny the truth of (a statement) by asserting the opposite.'),
(4095, 3, 2570, 'contradict oneself', 'contradict'),
(4096, 3, 2573, 'contradiction', 'a combination of statements, ideas, or features of a situation that are opposed to one another.'),
(4097, 3, 2915, 'harvest', 'the process or period of gathering in crops.'),
(4098, 3, 2092, 'production cost', 'prime cost'),
(4099, 3, 3107, 'discharged', 'tell (someone) officially that they can or must leave a place or situation.'),
(4100, 3, 2650, 'belt', 'a strip of leather or other material worn around the waist or across the chest, especially in order to support clothes or carry weapons.'),
(4101, 3, 2764, 'criticism', 'the expression of disapproval of someone or something based on perceived faults or mistakes.'),
(4102, 3, NULL, 'surprise', 'an unexpected or astonishing event, fact, or thing.'),
(4103, 3, 1693, 'sonorous', '(of a person\'s voice or other sound) imposingly deep and full.'),
(4104, 3, 1773, 'sorbet', 'a dessert consisting of frozen fruit juice or flavored water and sugar.'),
(4105, 3, 2611, 'anxiety', 'a feeling of worry, nervousness, or unease, typically about an imminent event or something with an uncertain outcome.');
