(2744, 2, NULL, 831, 'balance', 'movimiento de un cuerpo hacia un lado y hacia el otro.'),
(2745, 2, NULL, 979, 'balcón', 'ventana abierta hasta el suelo de la habitación, generalmente con prolongación voladiza, con barandilla.'),
(2746, 2, NULL, 1730, 'balada', 'canción de ritmo lento y de carácter popular, cuyo asunto es generalmente amoroso.'),
(2747, 2, NULL, 1855, 'banco', 'asiento, con respaldo o sin él, en que pueden sentarse dos o más personas.'),
(2748, 2, NULL, 3301, 'bancario', 'perteneciente o relativo a la banca o a los bancos (‖ empresas dedicadas a operaciones financieras).'),
(2749, 2, NULL, 702, 'bandera', 'tela de forma comúnmente rectangular, que se asegura por uno de sus lados a un asta o a una driza y se emplea como enseña o señal de una nación, una ciudad o una institución.'),
