(2757, 2, NULL, 1653, 'abeja', 'insecto himenóptero, de unos quince milímetros de largo, de color pardo negruzco y vello rojizo, que vive en colonias y produce cera y miel.'),
(2758, 2, NULL, 93, 'cerveza', 'bebida alcohólica hecha con granos germinados de cebada u otros cereales fermentados en agua, y aromatizada con lúpulo, boj, casia, etc.'),
(2759, 2, NULL, 1450, 'dormitorio', 'en una vivienda, habitación destinada para dormir.'),
