INSERT INTO `spanish_words` (`id`, `language_id`, `turkish_word_id`, `english_word_id`, `es_word`, `description`) VALUES
(2761, 2, NULL, 216, 'creencia', 'firme asentimiento y conformidad con algo.'),
(2762, 2, NULL, 2538, 'campana', 'instrumento metálico, generalmente en forma de copa invertida, que suena al ser golpeado por un badajo o por un martillo exterior.'),
(2763, 2, NULL, 96, 'factura', 'cuenta en que se detallan con su precio los artículos vendidos o los servicios realizados y que se entrega al cliente para exigir su pago.'),
(2764, 2, NULL, 1531, 'biología', 'ciencia que trata de los seres vivos considerando su estructura, funcionamiento, evolución, distribución y relaciones.'),
(2765, 2, NULL, 1624, 'pájaro', 'ave, especialmente si es pequeña.'),
(2766, 2, NULL, 352, 'cumpleaños', 'aniversario del nacimiento de una persona.'),
(2767, 2, NULL, 2233, 'pizarra', 'roca homogénea, de grano muy fino, comúnmente de color negro azulado, opaca, tenaz, que se divide con facilidad en hojas planas y delgadas, y que procede de una arcilla metamorfoseada por las acciones telúricas.'),
(2768, 2, NULL, 1595, 'sangre', 'líquido, generalmente de color rojo, que circula por las arterias y venas del cuerpo de los animales, se compone de una parte líquida o plasma y de células en suspensión:'),
(2769, 2, NULL, 710, 'azul', 'dicho de un color: semejante al del cielo sin nubes y el mar en un día soleado, y que ocupa el quinto lugar en el espectro luminoso. u. t. c. s. m.'),
(2770, 2, NULL, 29, 'embarque', 'acción y efecto de embarcar (‖ introducir personas u objetos en un medio de transporte).'),
(2771, 2, NULL, 1590, 'cuerpo', 'aquello que tiene extensión limitada, perceptible por los sentidos.'),
(2772, 2, NULL, 3385, 'cadáver', 'cuerpo muerto.'),
(2773, 2, NULL, 1869, 'prima', 'primero.'),
(2774, 2, NULL, 2125, 'reservar', 'guardar algo para lo futuro.'),
(2775, 2, NULL, 3362, 'libro', 'conjunto de muchas hojas de papel u otro material semejante que, encuadernadas, forman un volumen.'),
(2776, 2, NULL, 3131, 'aburrimiento', 'cansancio del ánimo originado por falta de estímulo o distracción, o por molestia reiterada.'),
(2777, 2, NULL, 1586, 'cerebro', 'uno de los centros nerviosos constitutivos del encéfalo, existente en todos los vertebrados y situado en la parte anterior y superior de la cavidad craneal.'),
(2778, 2, NULL, 1605, 'rama', 'cada una de las partes que nacen del tronco o tallo principal de la planta y en las cuales brotan por lo común las hojas, las flores y los frutos.'),
(2779, 2, NULL, 3432, 'sucursal', 'dicho de un establecimiento: que, situado en distinto lugar que la central de la cual depende, desempeña las mismas funciones que esta. u. t. c. s. f.'),
(2780, 2, NULL, 3060, 'valentía', 'cualidad de valiente.'),
(2781, 2, NULL, 2239, 'romper', 'separar con más o menos violencia las partes de un todo, deshaciendo su unión. u. t. c. prnl.'),
(2782, 2, NULL, 84, 'desayuno', 'primera comida del día, generalmente ligera, que se toma por la mañana.'),
(2783, 2, NULL, 3413, 'brisa', 'viento suave.'),
(2784, 2, NULL, 489, 'puente', 'construcción de piedra, ladrillo, madera, hierro, hormigón, etc., que se construye y forma sobre los ríos, fosos y otros sitios, para poder pasarlos. era u. t. c. f. dialectalmente, u. c. f.'),
(2785, 2, NULL, 506, 'brillo', 'luz que refleja o emite un cuerpo.'),
(2786, 2, NULL, 1118, 'marrón', 'piedra con que se juega al marro.'),
(2787, 2, NULL, 1499, 'cepillar', 'quitar el polvo o la suciedad a algo con un cepillo de cerdas u otro objeto que desempeñe la misma función. u. t. c. prnl.'),
(2788, 2, NULL, 1950, 'presupuesto', 'motivo, causa o pretexto con que se ejecuta algo.'),
(2789, 2, NULL, 1266, 'edificio', 'construcción estable, hecha con materiales resistentes, para ser habitada o para otros usos.'),
(2790, 2, NULL, 3467, 'quemar', 'dicho del fuego: destruir algo o a alguien. u. t. c. prnl.'),
(2791, 2, NULL, 3439, 'arbusto', 'planta leñosa, de menos de cinco metros de altura, sin un tronco preponderante, porque se ramifica a partir de la base.'),
(2792, 2, NULL, 1924, 'negocio', 'ocupación, quehacer o trabajo.'),
