(2794, 2, NULL, 1997, 'desarrollo', 'acción y efecto de desarrollar o desarrollarse.'),
(2795, 2, NULL, 3477, 'rocío', 'vapor que con la frialdad de la noche se condensa en la atmósfera en muy menudas gotas, las cuales aparecen luego sobre la superficie de la tierra o sobre las plantas.'),
