(2797, 2, NULL, 1715, 'calígrafo', 'persona que escribe a mano con letra excelente.'),
(2798, 2, NULL, 1647, 'camello', 'mamífero artiodáctilo rumiante, oriundo del asia central, corpulento y más alto que el caballo, con el cuello largo, la cabeza proporcionalmente pequeña y dos gibas en el dorso, formadas por acumulación de tejido adiposo. u. en m. ref. a la especie.'),
(2799, 2, NULL, 1363, 'cámara', 'sala o pieza principal de una casa.'),
