(2804, 2, NULL, 99, 'dinero', 'moneda corriente.'),
(2805, 2, NULL, 470, 'tope', 'parte por donde algo puede topar con otra cosa.'),
(2806, 2, NULL, 1461, 'cielo raso', 'ceiling'),
(2807, 2, NULL, 1348, 'celebración', 'acción de celebrar.'),
(2808, 2, NULL, 1588, 'célula', 'unidad fundamental de los organismos vivos, capaz de reproducción independiente y formada por un citoplasma rodeado por una membrana.'),
(2809, 2, NULL, 350, 'ceremonia', 'acción o acto exterior arreglado, por ley, estatuto o costumbre, para dar culto a las cosas divinas, o reverencia y honor a las profanas.'),
(2810, 2, NULL, 1467, 'silla', 'asiento con respaldo, por lo general con cuatro patas, y en que solo cabe una persona.'),
