(3043, 2, NULL, 58, 'percha', 'pieza o mueble de madera o metal con colgaderos en que se pone ropa, sombreros u otros objetos, y que puede estar sujeto a la pared o constar de un palo largo y de un pie para que apoye en el suelo.'),
(3044, 2, NULL, 3006, 'felicidad', 'estado de grata satisfacción espiritual y física.'),
(3045, 2, NULL, 2666, 'hardware', 'tools, machinery, and other durable equipment.'),
(3046, 2, NULL, 3013, 'odiar', 'tener odio.'),
(3047, 2, NULL, 3382, 'titular', 'dicho de una persona: que ejerce un cargo o una profesión con título o nombramiento oficiales.'),
(3048, 2, NULL, 482, 'patio', 'espacio cerrado con paredes o galerías, que en las casas y otros edificios se suele dejar al descubierto.'),
(3049, 2, NULL, 1649, 'cebra', 'animal solípedo del áfrica austral, parecido al asno, de pelo blanco amarillento, con listas transversales pardas o negras. hay varias especies, y alguna del tamaño del caballo.'),
(3050, 2, NULL, 240, 'culto', 'dotado de las calidades que provienen de la cultura o instrucción.'),
