(3052, 2, NULL, 94, 'vino', 'bebida alcohólica que se hace del zumo de las uvas exprimido y fermentado naturalmente.'),
(3053, 2, NULL, 1658, 'gusano', 'any of a number of creeping or burrowing invertebrate animals with long, slender soft bodies and no limbs.'),
(3054, 2, NULL, 3428, 'mundo', 'conjunto de todo lo existente.'),
(3055, 2, NULL, 1827, 'lugar de trabajo', 'el lugar de trabajo'),
(3056, 2, NULL, 3351, 'palabra', 'unidad lingüística, dotada generalmente de significado, que se separa de las demás mediante pausas potenciales en la pronunciación y blancos en la escritura.'),
(3057, 2, NULL, 3367, 'escribiendo', 'representar las palabras o las ideas con letras u otros signos trazados en papel u otra superficie.'),
(3058, 2, NULL, 1425, 'esposa', 'persona casada, con relación a su cónyuge.'),
(3059, 2, NULL, 3499, 'salvaje', 'dicho de una planta: que ha crecido sin ser cultivada.'),
(3060, 2, NULL, 2175, 'ganar', 'adquirir caudal o aumentarlo con cualquier género de comercio, industria o trabajo.'),
(3061, 2, NULL, 3405, 'viento', 'corriente de aire producida en la atmósfera por causas naturales, como diferencias de presión o temperatura.'),
(3062, 2, NULL, 445, 'ancho', 'que tiene más o menos anchura.'),
(3063, 2, NULL, 1559, 'peso', 'fuerza con que la tierra atrae a un cuerpo.'),
