(3072, 2, NULL, 1641, 'loba', 'sotana'),
(3073, 2, NULL, 1687, 'cachorro de lobo', 'cachorro de lobo'),
(3074, 2, NULL, 1664, 'ballena', 'cetáceo, el mayor de todos los animales conocidos, que llega a crecer hasta más de 30 m de longitud. su color es, en general, oscuro por encima y blanquecino por debajo. vive en todos los mares, preferentemente en los polares.'),
