(3097, 2, NULL, 457, 'triángulo', 'de forma de triángulo.'),
(3098, 2, NULL, 1603, 'árbol', 'planta de tallo leñoso y elevado, que se ramifica a cierta altura del suelo.'),
(3099, 2, NULL, 2989, 'capacitación', 'acción y efecto de capacitar.'),
(3100, 2, NULL, 1818, 'aprendiz', 'persona que aprende algún arte u oficio.'),
