(3117, 2, NULL, 3313, 'hablar', 'emitir palabras.'),
(3118, 2, NULL, 77, 'mesa', 'mueble compuesto de un tablero horizontal liso y sostenido a la altura conveniente, generalmente por una o varias patas, para diferentes usos, como escribir, comer, etc.'),
