(3136, 2, NULL, 1591, 'esqueleto', 'conjunto de piezas duras y resistentes, por lo regular trabadas o articuladas entre sí, que da consistencia al cuerpo de los animales, sosteniendo o protegiendo sus partes blandas.'),
(3137, 2, NULL, 443, 'tamaño', 'tan grande o tan pequeño.'),
(3138, 2, NULL, 52, 'ducha', 'acción y efecto de duchar.'),
