(3174, 2, NULL, 2178, 'jugador', 'que juega. apl. a pers., u. m. c. s.'),
(3175, 2, NULL, 1538, 'planeta', 'cuerpo celeste sin luz propia que gira en una órbita elíptica alrededor de una estrella, en particular los que giran alrededor del sol'),
