(3215, 2, NULL, 3352, 'carta', 'papel escrito, y ordinariamente cerrado, que una persona envía a otra para comunicarse con ella.'),
(3216, 2, NULL, 72, 'lámpara', 'utensilio o aparato que, colgado o sostenido sobre un pie, sirve de soporte a una o varias luces artificiales.'),
