(3219, 2, NULL, 1523, 'invención', 'acción y efecto de inventar.'),
(3220, 2, NULL, 1849, 'ingreso', 'acción de ingresar.'),
(3221, 2, NULL, 230, 'habitante', 'que habita'),
(3222, 2, NULL, 1631, 'caballo', 'mamífero solípedo del orden de los perisodáctilos, de tamaño grande y extremidades largas, cuello y cola poblados de cerdas largas y abundantes, que se domestica fácilmente y suele utilizarse como montura o animal de tiro.'),
