(3233, 2, NULL, 39, 'viajar', 'trasladarse de un lugar a otro, generalmente distante, por cualquier medio de locomoción.'),
(3234, 2, NULL, 42, 'recorrido', 'acción y efecto de recorrer.'),
(3235, 2, NULL, 3408, 'abstracta', 'que significa alguna cualidad con exclusión del sujeto.'),
(3236, 2, NULL, 44, 'complejo', 'que se compone de elementos diversos.'),
(3237, 2, NULL, 46, 'reception', 'the action or process of receiving something sent, given, or inflicted.'),
(3238, 1, NULL, NULL, 'televisión', 'sistema de transmisión de imágenes a distancia a través de diferentes medios electromagnéticos, y que se reproducen posteriormente en un aparato receptor.'),
(3239, 2, NULL, 87, 'bocadillo', 'pieza de pan abierta, o conjunto de dos rebanadas, en cuyo interior se coloca o se unta algún alimento.'),
(3240, 2, NULL, 90, 'jugo', 'zumo de las sustancias animales o vegetales sacado por presión, cocción o destilación.'),
(3241, 2, NULL, 208, 'museo', 'lugar en que se conservan y exponen colecciones de objetos artísticos, científicos, etc.'),
(3242, 2, NULL, 229, 'residente', 'que reside'),
(3243, 2, NULL, 243, 'templo', 'edificio o lugar destinado pública y exclusivamente a un culto.'),
(3244, 2, NULL, 83, 'comida', 'lo que se come y bebe para nutrirse.'),
(3245, 2, NULL, 1791, 'interpretación', 'acción y efecto de interpretar.'),
(3246, 2, NULL, 265, 'video', 'grabación hecha en video.'),
(3247, 2, NULL, 266, 'registro', 'acción de registrar.'),
(3248, 2, NULL, 271, 'historia', 'narración y exposición de los acontecimientos pasados y dignos de memoria, sean públicos o privados.'),
(3249, 2, NULL, 272, 'leyenda', 'narración de sucesos fantásticos que se transmite por tradición.'),
(3250, 2, NULL, 299, 'revolución', 'acción y efecto de revolver o revolverse.'),
(3251, 2, NULL, 273, 'mito', 'vigesimoprimera letra del abecedario español, que representa el fonema consonántico oclusivo dental sordo.'),
(3252, 2, NULL, 307, 'microbús', 'autobús de menor tamaño que el usual.'),
(3253, 2, NULL, 322, 'norma', 'regla que se debe seguir o a que se deben ajustar las conductas, tareas, actividades, etc.'),
(3254, 2, NULL, 323, 'sociedad', 'conjunto de personas, pueblos o naciones que conviven bajo normas comunes.'),
(3255, 2, NULL, 327, 'población', 'acción y efecto de poblar.'),
(3256, 2, NULL, 334, 'refugiado', 'persona que, a consecuencia de guerras, revoluciones o persecuciones políticas, se ve obligada a buscar refugio fuera de su país.'),
(3257, 2, NULL, 1416, 'primo', 'primero'),
(3258, 2, NULL, 1333, 'emigrante', 'que emigra'),
(3259, 2, NULL, 1716, 'tintero', 'recipiente en que se pone la tinta de escribir.'),
(3260, 2, NULL, 421, 'matiz', 'rasgo poco perceptible que da a algo un carácter determinado.'),
(3261, 2, NULL, 3040, 'humildad', 'virtud que consiste en el conocimiento de las propias limitaciones y debilidades y en obrar de acuerdo con este conocimiento.'),
(3262, 2, NULL, 1424, 'marido', 'hombre casado, con relación a su cónyuge.'),
(3263, 2, NULL, 1775, 'hipérbole', 'figura que consiste en aumentar o disminuir exageradamente aquello de que se trata.'),
(3264, 2, NULL, 1444, 'casa', 'edificio para habitar.'),
(3265, 2, NULL, 1519, 'hipótesis', 'suposición de algo posible o imposible para sacar de ello una consecuencia.'),
(3266, 2, NULL, 1736, 'imágenes', 'figura, representación, semejanza y apariencia de algo.'),
(3267, 2, NULL, 1508, 'conocimiento', 'acción y efecto de conocer.'),
(3268, 2, NULL, 1871, 'seguro', 'libre y exento de riesgo.'),
(3269, 2, NULL, 1817, 'interna', 'interior.'),
(3270, 2, NULL, 1601, 'intestino', 'interior, interno.'),
(3271, 2, NULL, 3384, 'introducción', 'acción y efecto de introducir o introducirse.'),
(3272, 2, NULL, 1773, 'ironía', 'burla fina y disimulada.'),
(3273, 2, NULL, 1860, 'factura', 'cuenta en que se detallan con su precio los artículos vendidos o los servicios realizados y que se entrega al cliente para exigir su pago.'),
(3274, 2, NULL, 1710, 'irregularidad', 'cualidad de irregular.'),
(3275, 2, NULL, 3451, 'isla', 'porción de tierra rodeada de agua por todas partes.'),
(3276, 2, NULL, 3035, 'celos', 'cuidado, diligencia, esmero que alguien pone al hacer algo.'),
(3277, 2, NULL, 1803, 'trabajo', 'acción y efecto de trabajar.'),
(3278, 1, NULL, 1679, 'canguro', 'mamífero marsupial, herbívoro, propio de australia e islas adyacentes, con las extremidades posteriores muy desarrolladas, mediante las cuales se traslada a saltos, y de cola muy robusta, en la que se apoya cuando está parado.'),
(3279, 2, NULL, 2157, 'teclado', 'conjunto de las teclas de un piano u otro instrumento musical.'),
(3280, 2, NULL, 49, 'llave', 'instrumento, comúnmente metálico, que, introducido en una cerradura, permite activar el mecanismo que la abre y la cierra.'),
(3281, 2, NULL, 1599, 'riñón', 'cada uno de los órganos excretores, generalmente en número par, que filtran la sangre para eliminar los residuos del metabolismo en forma de orina.'),
(3282, 2, NULL, 1442, 'familiares', 'perteneciente o relativo a la familia.'),
(3283, 2, NULL, 3308, 'amabilidad', 'cualidad de amable.'),
(3284, 2, NULL, 1510, 'aprendiendo', 'adquirir el conocimiento de algo por medio del estudio o de la experiencia.'),
(3285, 2, NULL, 1689, 'gatita', 'gatita'),
(3286, 2, NULL, 1856, 'préstamo', 'acción y efecto de prestar (‖ entregar algo a alguien para que lo devuelva).'),
(3287, 2, NULL, 2153, 'biblioteca', 'institución cuya finalidad consiste en la adquisición, conservación, estudio y exposición de libros y documentos.'),
(3288, 2, NULL, 2176, 'perder', 'perder'),
(3289, 2, NULL, 1597, 'pulmón', 'órgano o cada uno de los dos órganos de la respiración del hombre y de los vertebrados que viven o pueden vivir fuera del agua, de estructura esponjosa, blando, flexible, que se comprime y se dilata, y ocupa una parte de la cavidad torácica.\r\nsynonyms:\r\n\r\n    bofe \r\n\r\n2\r\nzoología\r\nórgano respiratorio de los moluscos terrestres, que consiste en una cavidad cuyas paredes están provistas de numerosos vasos sanguíneos y que comunica con el exterior mediante un orificio por el cual penetra el aire atmosférico.'),
(3290, 2, NULL, 1644, 'ratón', 'mamífero roedor de pequeño tamaño, de hocico puntiagudo y cola larga, de pelaje corto. u. en m. ref. a la especie.'),
(3291, 2, NULL, 1733, 'metáfora', 'traslación del sentido recto de una voz a otro figurado, en virtud de una comparación tácita, como en las perlas del rocío, la primavera de la vida o refrenar las pasiones.'),
(3292, 2, NULL, 1587, 'nervio', 'conjunto de fibras nerviosas en forma de cordón blanquecino que conducen impulsos entre el sistema nervioso central y otras partes del cuerpo.'),
(3293, 2, NULL, 1693, 'nido', 'especie de lecho que forman las aves con hierbas, pajas, plumas u otros materiales blandos, para poner sus huevos y criar los pollos. unas utilizan con tal fin los agujeros de las peñas, ribazos, troncos o edificios; otras lo construyen de ramas, o de barro, o de sustancias gelatinosas, dándole forma cóncava, y lo suspenden de los árboles o lo asientan en ellos, en las rocas o en las paredes, y algunas prefieren el suelo sin otro abrigo que la hierba y la tierra.'),
(3294, 2, NULL, 3325, 'noción', 'conocimiento o idea que se tiene de algo.'),
(3295, 2, NULL, 1767, 'omnisciente', 'que tiene omnisciencia.'),
(3296, 2, NULL, 3321, 'opinión', 'juicio o valoración que se forma una persona respecto de algo o de alguien.'),
(3297, 2, NULL, 1708, 'orden', 'colocación de las cosas en el lugar que les corresponde.');
